import type { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ReactNode } from 'react';
export interface ButtonBannerProps {
    label: string;
    onClick?: () => void;
    startIcon?: ReactNode;
    variant?: 'overlay' | 'outlined';
}
export type BannerActions = ButtonBannerProps[] & {
    0?: ButtonBannerProps;
    1?: ButtonBannerProps;
};
export type ContainerColorVariants = 'info' | 'success' | 'warning' | 'error' | 'default';
export type BannerTypeVariants = 'horizontal' | 'vertical';
export interface BannerProps {
    /** Текст баннера */
    title: ReactNode;
    /** Цвет фона баннера и иконки */
    color?: ContainerColorVariants;
    /** Тип баннера (с кнопками, без, с кнопкой крестиком закрытия в правом верхнем углу ) */
    type?: BannerTypeVariants;
    /** Массив из двух объектов с параметрами для кнопок, отображаются справа от текста баннера
     * @param label: string - Название кнопки.
     * @param onClick: () => void - Событие клика по кнопке.
     * @param startIcon?: ReactNode - Компонент иконки, отображается в начале названия кнопки
     */
    actions?: BannerActions;
    /** Событие закрытия баннера, при клике по крестику в правом верхнем углу */
    onClose?: () => void;
    /** Название иконки отображаемой слева от текста баннера */
    iconName?: Icons;
    /** Пользовательский класс*/
    className?: string;
}
